import { FastifyRequest, FastifyReply } from 'fastify';
import { LeaveService } from './leave.service';
import { BalanceService } from '../balance/balance.service';
import { CreateLeaveRequestDto, UpdateLeaveRequestDto, LeaveRequest } from './leave.model';
import { LeaveBalance } from '../balance/balance.model';
import { AuthenticatedRequest } from '../../shared/types/auth';

export class LeaveController {
  constructor(
    private readonly leaveService: LeaveService,
    private readonly balanceService: BalanceService
  ) {}

  async applyLeave(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const dto: CreateLeaveRequestDto = request.body;
    const employeeId = request.user.id;
    const leaveRequest = await this.leaveService.applyLeave(employeeId, dto);
    reply.code(201).send(leaveRequest);
  }

  async approveLeave(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const { id } = request.params as { id: string };
    const approverId = request.user.id;
    const leaveRequest = await this.leaveService.approveLeave(id, approverId);
    reply.send(leaveRequest);
  }

  async rejectLeave(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const { id } = request.params as { id: string };
    const approverId = request.user.id;
    const reason = (request.body as any)?.reason;
    const leaveRequest = await this.leaveService.rejectLeave(id, approverId, reason);
    reply.send(leaveRequest);
  }

  async cancelLeave(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const { id } = request.params as { id: string };
    const employeeId = request.user.id;
    const leaveRequest = await this.leaveService.cancelLeave(id, employeeId);
    reply.send(leaveRequest);
  }

  async getLeaveRequest(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const { id } = request.params as { id: string };
    const leaveRequest = await this.leaveService.getLeaveRequest(id);
    reply.send(leaveRequest);
  }

  async getLeaveRequests(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const filters = request.query as any;
    const leaveRequests = await this.leaveService.getLeaveRequests(filters);
    reply.send(leaveRequests);
  }

  async getLeaveBalance(request: AuthenticatedRequest, reply: FastifyReply): Promise<void> {
    const employeeId = request.user.id;
    const { leaveTypeId, year } = request.query as any;
    const balance = await this.balanceService.getBalance(employeeId, leaveTypeId, year);
    reply.send(balance);
  }
}","File: src/modules/leave/leave.routes.ts
import { FastifyInstance } from 'fastify';
import { LeaveController } from './leave.controller';
import { applyLeaveSchema, approveLeaveSchema, rejectLeaveSchema, cancelLeaveSchema, getLeaveRequestSchema, getLeaveRequestsSchema, getLeaveBalanceSchema } from './leave.schemas';
import { AuthenticatedRequest } from '../../shared/types/auth';

export function registerLeaveRoutes(fastify: FastifyInstance, leaveController: LeaveController): void {
  fastify.post('/apply', { schema: applyLeaveSchema, preHandler: [fastify.authenticate, fastify.authorize('employee')] }, leaveController.applyLeave.bind(leaveController));
  fastify.put('/approve/:id', { schema: approveLeaveSchema, preHandler: [fastify.authenticate, fastify.authorize('manager')] }, leaveController.approveLeave.bind(leaveController));
  fastify.put('/reject/:id', { schema: rejectLeaveSchema, preHandler: [fastify.authenticate, fastify.authorize('manager')] }, leaveController.rejectLeave.bind(leaveController));
  fastify.put('/cancel/:id', { schema: cancelLeaveSchema, preHandler: [fastify.authenticate, fastify.authorize('employee')] }, leaveController.cancelLeave.bind(leaveController));
  fastify.get('/:id', { schema: getLeaveRequestSchema, preHandler: [fastify.authenticate] }, leaveController.getLeaveRequest.bind(leaveController));
  fastify.get('/', { schema: getLeaveRequestsSchema, preHandler: [fastify.authenticate] }, leaveController.getLeaveRequests.bind(leaveController));
  fastify.get('/balance', { schema: getLeaveBalanceSchema, preHandler: [fastify.authenticate] }, leaveController.getLeaveBalance.bind(leaveController));
}","File: src/shared/di/container.ts
