  const employeeRepository = new EmployeeRepository(fastify.db);

  const leaveService = new LeaveService(leaveRepository, balanceRepository, employeeRepository);
  const balanceService = new BalanceService(balanceRepository);
  const employeeService = new EmployeeService(employeeRepository);

  const leaveController = new LeaveController(leaveService, balanceService);

  registerLeaveRoutes(fastify, leaveController);
